<?php
require_once __DIR__.'/../../config.php';redirect_if_not_logged_in();require_permission($pdo,'view_reports');require_once __DIR__.'/../_shared/workspace.php';ensure_maorin_workspace_tables($pdo);$stats=[];$stats['projects']=$pdo->query("SELECT COUNT(*) c,COALESCE(SUM(contract_amount),0) contract,COALESCE(SUM(actual_cost),0) cost FROM mb_projects")->fetch(PDO::FETCH_ASSOC);$stats['expenses']=$pdo->query("SELECT COALESCE(SUM(amount),0) amount FROM mb_expenses")->fetch(PDO::FETCH_ASSOC);$stats['inventory']=$pdo->query("SELECT COALESCE(SUM(quantity*unit_cost),0) value,SUM(CASE WHEN quantity<=min_quantity THEN 1 ELSE 0 END) low_stock FROM mb_inventory_items")->fetch(PDO::FETCH_ASSOC);$stats['invoices']=$pdo->query("SELECT COALESCE(SUM(amount),0) amount,COALESCE(SUM(paid_amount),0) paid FROM mb_invoices")->fetch(PDO::FETCH_ASSOC);$projectRows=$pdo->query("SELECT name,status,progress_percent,contract_amount,actual_cost,(contract_amount-actual_cost) profit FROM mb_projects ORDER BY updated_at DESC LIMIT 20")->fetchAll(PDO::FETCH_ASSOC);mb_workspace_header($pdo,'Reports','Reports');?>
<div class="row g-3 mb-3"><div class="col-md-3"><div class="mb-stat"><div class="mb-stat-label">Projects</div><div class="mb-stat-value"><?=(int)$stats['projects']['c']?></div></div></div><div class="col-md-3"><div class="mb-stat"><div class="mb-stat-label">Project Profit</div><div class="mb-stat-value">₱<?=mb_money($stats['projects']['contract']-$stats['projects']['cost'])?></div></div></div><div class="col-md-3"><div class="mb-stat"><div class="mb-stat-label">Expenses</div><div class="mb-stat-value">₱<?=mb_money($stats['expenses']['amount'])?></div></div></div><div class="col-md-3"><div class="mb-stat"><div class="mb-stat-label">Receivables</div><div class="mb-stat-value">₱<?=mb_money($stats['invoices']['amount']-$stats['invoices']['paid'])?></div></div></div></div><div class="mb-card"><div class="mb-card-header"><strong>Project Cost / Profit Summary</strong></div><div class="table-responsive"><table class="table mb-table"><thead><tr><th>Project</th><th>Status</th><th>Progress</th><th>Contract</th><th>Cost</th><th>Profit</th></tr></thead><tbody><?php foreach($projectRows as $r):?><tr><td><?=htmlspecialchars($r['name'])?></td><td><span class="mb-badge"><?=htmlspecialchars($r['status'])?></span></td><td><?=(int)$r['progress_percent']?>%</td><td>₱<?=mb_money($r['contract_amount'])?></td><td>₱<?=mb_money($r['actual_cost'])?></td><td>₱<?=mb_money($r['profit'])?></td></tr><?php endforeach;if(!$projectRows):?><tr><td colspan="6" class="text-center text-muted py-4">No report data yet.</td></tr><?php endif;?></tbody></table></div></div><?php mb_workspace_footer();?>